const original = $('Extract Candidate Data').first().json;

const aiText = $json.choices[0].message.content;

const cleaned = aiText
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

const parsed = JSON.parse(cleaned);

return [
  {
    json: {
      ...original,
      candidate_summary: parsed.candidate_summary,
      skills: Array.isArray(parsed.skills) ? parsed.skills.join(", ") : parsed.skills,
      years_experience: parsed.years_experience,
      strengths: Array.isArray(parsed.strengths) ? parsed.strengths.join(", ") : parsed.strengths,
      weaknesses: Array.isArray(parsed.weaknesses) ? parsed.weaknesses.join(", ") : parsed.weaknesses,
      score: Number(parsed.score),
      recommendation: parsed.recommendation,
      reason: parsed.reason,
      interview_questions: Array.isArray(parsed.interview_questions)
        ? parsed.interview_questions.join("\n")
        : parsed.interview_questions
    }
  }
];
